let calendar;

$(document).ready(function () {
  // Initialize the calendar
  initializeCalendar();

  // Attach event handlers
  initializeEventHandlers();

  // Initialize date pickers
  initializeDatePickers();

  // Initialize draggable events
  initializeDraggableEvents();
});

// Initialize FullCalendar
function initializeCalendar() {
  const calendarEl = document.getElementById("calendar");

  if (!calendarEl) {
    console.warn("Calendar element not found.");
    return;
  }

  calendar = new FullCalendar.Calendar(calendarEl, {
    plugins: ["interaction", "dayGrid", "timeGrid"],
    header: {
      left: "prev,next today",
      center: "title",
      right: "dayGridMonth,timeGridWeek,timeGridDay",
    },
    editable: true,
    droppable: true,
    selectable: true,
    navLinks: true,
    eventLimit: true,
    weekNumberCalculation: "ISO",
    displayEventTime: false, // Hides time for all events
    events: loadEvents(),
    eventContent: renderEventContent, // Render custom event display
    eventMouseEnter: handleEventMouseEnter, // Show popover on hover
    eventMouseLeave: handleEventMouseLeave, // Hide popover on mouse leave
    select: handleEventSelect, // Handle new event selection
    eventClick: handleEventClick, // Handle event editing
  });

  // When the calendar view changes
calendar.on('datesSet', function(info) {
  const year = info.start.getFullYear();
  const month = info.start.getMonth() + 1; // JS months are 0-indexed

  // Reload calendar events via AJAX or by submitting the form
  $('#server_request').val('Y');
  $('<input>').attr({
    type: 'hidden',
    name: 'month',
    value: month
  }).appendTo('#myForms');

  $('<input>').attr({
    type: 'hidden',
    name: 'year',
    value: year
  }).appendTo('#myForms');

  $('#myForms').submit();
});

  calendar.render();
}

