function loadEvents() {
  return attendanceEvents.map((event) => ({
    id: event.id,
    title: event.title,
    start: new Date(event.start),
    end: new Date(event.end),
    description: event.description || "No details available.",
    missing_details: event.missing_details || [],
    className: "fc-event-danger" // red color for missing attendance
  }));
}


// Render custom event content
function renderEventContent(arg) {
  return {
    html: `
      <div>
        <div>${arg.event.title.split("\n")[0]}</div> <!-- Guest Name & Mobile -->
        <div style="font-size: 0.8em; color: gray;">${arg.event.extendedProps.followStatus}</div> <!-- Follow-up Status -->
      </div>
    `,
  };
}

function handleEventMouseEnter(info) {
  // Format the date safely
  const date = FullCalendar.formatDate(info.event.start, {
    year: "numeric",
    month: "short",
    day: "2-digit",
  });

  // Safely get missing details
  const missingDetails = info.event.extendedProps.missing_details || [];
  let detailsHTML = "";

  // Build list items for missing periods
  missingDetails.forEach((d) => {
    detailsHTML += `
      <li>
        Period: <strong>${d.period}</strong><br />
        Subject: <strong>${d.subject}</strong><br />
        Faculty: <strong>${d.faculty}</strong><br />
        Semester: <strong>${d.semester}</strong><br />
        Course: <strong>${d.course}</strong>
      </li>`;
  });

  // Ensure jQuery and Bootstrap Popover are available
  if (typeof $ === "undefined" || !$.fn.popover) {
    console.warn("jQuery or Bootstrap Popover not loaded properly.");
    return;
  }

  // Dispose old popovers before showing new one
  $(info.el).popover("dispose");

  // Initialize the new popover
  $(info.el).popover({
    title: `<strong>Missing Attendance - ${date}</strong>`,
    content: `<ul>${detailsHTML}</ul>`,
    html: true,
    placement: "top",
    container: "body",
    trigger: "manual",
  });

  // Show popover manually
  $(info.el).popover("show");
}


// Hide popover on mouse leave
function handleEventMouseLeave(info) {
  $(info.el).popover("dispose");
}

// Handle event selection (for creating new events)
function handleEventSelect(info) {
  $("#add-event").show();
  $("#edit-event").hide();
  $("#addEventTitle").show();
  $("#editEventTitle").hide();

  clearModalForm();
  $(".modal").modal("show");
}

