// Initialize draggable events
function initializeDraggableEvents() {
  const containerEl = document.getElementById("external-events");

  if (!containerEl) return;

  new FullCalendar.Draggable(containerEl, {
    itemSelector: ".fc-event",
    eventData: function (eventEl) {
      return {
        title: eventEl.innerText,
        className: eventEl.dataset.class,
      };
    },
  });
}

// Initialize date pickers
function initializeDatePickers() {
  flatpickr("#starts-at", {
    enableTime: true,
    allowInput: true,
    dateFormat: "Y-m-d H:i",
    onOpen: function (selectedDates, dateStr, instance) {
      instance.setDate(instance.input.value, false);
    },
  });

  flatpickr("#ends-at", {
    enableTime: true,
    allowInput: true,
    dateFormat: "Y-m-d H:i",
    onOpen: function (selectedDates, dateStr, instance) {
      instance.setDate(instance.input.value, false);
    },
  });
}

// Initialize modal event handlers
function initializeEventHandlers() {
  $("#add-event").on("click", function () {
    const title = $("#title").val().trim() || "Untitled Event";
    const description = $("#eventDetails").val().trim() || "No details available.";
    const category = $("#categorySelect").val();
    const randomID = randomIDGenerate(10);

    calendar.addEvent({
      id: randomID,
      title: title,
      start: $("#starts-at").val(),
      end: $("#ends-at").val(),
      className: category,
      description: description,
    });

    $(".modal").modal("hide");
    clearModalForm();
  });

  $("#edit-event").on("click", function () {
    const id = $("#id").val();
    const event = calendar.getEventById(id);

    if (event) {
      event.setProp("title", $("#title").val());
      event.setStart($("#starts-at").val());
      event.setEnd($("#ends-at").val());
      event.setProp("className", $("#categorySelect").val());
      event.setExtendedProp("description", $("#eventDetails").val());
    }

    $(".modal").modal("hide");
    clearModalForm();
  });
}

// Clear modal form fields
function clearModalForm() {
  $(".modal").find("input, textarea").val("");
}

// Generate a random ID
function randomIDGenerate(length) {
  const chars = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
  let result = "";
  for (let i = 0; i < length; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}
